import api from '../app/client';

export const permissionService = {
  getAllPermissionsGrouped: () =>
    api.get('/permissions').then(r => r.data),

  getUserPermissions: (userId: string) =>
    api.get(`/permissions/users/${userId}`).then(r => r.data),

  setUserPermissions: (userId: string, assignments: Array<{ permissionId: string; granted: boolean }>) =>
    api.put(`/permissions/users/${userId}`, { assignments }).then(r => r.data),
};
